import React from "react";
import { useNavigate } from "react-router-dom";

const Home = () => {
  const nav = useNavigate();

  return (
    <div style={styles.container}>

      <div style={styles.card}>
        <h1>Daily Worker Platform</h1>
        <p>Hire workers instantly or find jobs easily</p>

        <button onClick={() => nav("/login")} style={styles.btn}>
          Get Started
        </button>
      </div>

    </div>
  );
};

export default Home;

const styles = {
  container: {
    height: "100vh",
    background: "#0b1220",
    display: "flex",
    justifyContent: "center",
    alignItems: "center",
    color: "white"
  },

  card: {
    background: "#111a2e",
    padding: "40px",
    borderRadius: "15px",
    textAlign: "center"
  },

  btn: {
    marginTop: "15px",
    background: "#22c55e",
    border: "none",
    padding: "10px 20px",
    color: "white",
    borderRadius: "8px"
  }
};
